// Filter clusters that already have a curated_post (avoid duplicates)
const clusters = Array.isArray(items[0]?.json) ? items[0].json : items.map(i => i.json);
if (!clusters || clusters.length === 0) return [];
return clusters.map(c => ({ json: c }));

const cluster = $('Normalize Input').item.json;
const sources = Array.isArray($json) ? $json : [$json];

const sourceTexts = sources.map((s, i) => {
  return `Fonte ${i + 1} (${s.source_name || 'desconhecido'}):
Titulo: ${s.title || ''}
Resumo: ${s.summary || s.content || ''}
URL: ${s.canonical_url || ''}`;
}).join('

');

const topicMap = {
  'ia': 'Inteligência Artificial',
  'ciberseguranca': 'Cibersegurança',
  'automacao': 'Automação',
  'geral': 'Tecnologia'
};

const topicLabel = topicMap[cluster.topic] || cluster.topic || 'Tecnologia';

const prompt = `Es um jornalista tecnologico portugues do portal Vision7. Escreve um artigo ORIGINAL baseado nas fontes abaixo.

REGRAS:
- Artigo 100% original, NAO copies frases das fontes
- Tom informativo e profissional, portugues europeu
- Entre 300 e 600 palavras
- Inclui titulo atrativo (sem clickbait)
- Inclui subtitulo de 1 linha
- Inclui excerpt (resumo de 2 frases)
- Corpo em Markdown
- Tema: ${topicLabel}
- NAO inventes dados ou estatisticas
- Cita fontes quando relevante

FONTES:
${sourceTexts}

Responde APENAS em JSON valido:
{
  "title": "...",
  "subtitle": "...",
  "excerpt": "...",
  "body_markdown": "...",
  "topic": "${cluster.topic}"
}`;

return [{
  json: {
    cluster_id: cluster.id,
    fingerprint: cluster.fingerprint,
    confidence_score: cluster.confidence_score,
    source_count: sources.length,
    topic: cluster.topic,
    prompt: prompt
  }
}];

