const prev = $('Build AI Prompt').item.json;
const response = $json;

// Parse AI response
let article;
try {
  const content = response.choices[0].message.content;
  // Remove markdown code fences if present
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  article = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse AI response: ' + e.message, cluster_id: prev.cluster_id, skip: true } }];
}

// AUDIT: validate quality
const audit = {
  has_title: Boolean(article.title && article.title.length > 10),
  has_body: Boolean(article.body_markdown && article.body_markdown.length > 200),
  has_excerpt: Boolean(article.excerpt && article.excerpt.length > 20),
  body_length: (article.body_markdown || '').length,
  no_suspicious_urls: !/https?:\/\/(?!vision7|google|microsoft|apple|meta)/i.test(article.body_markdown || ''),
  language_ok: /[áàãâéêíóôõúç]/i.test(article.body_markdown || '') // Portuguese chars present
};

const passedChecks = Object.values(audit).filter(v => v === true).length;
const totalChecks = Object.keys(audit).length - 1; // exclude body_length (numeric)
const editorial_score = Math.round((passedChecks / totalChecks) * 100);

// Generate slug from title
const slug = (article.title || 'sem-titulo')
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 80)
  + '-' + Date.now().toString(36);

return [{
  json: {
    cluster_id: prev.cluster_id,
    fingerprint: prev.fingerprint,
    title: article.title || 'Sem titulo',
    subtitle: article.subtitle || null,
    slug: slug,
    excerpt: article.excerpt || null,
    body_markdown: article.body_markdown || '',
    body_html: null,
    language: 'pt',
    editorial_score: editorial_score,
    confidence_score: prev.confidence_score,
    status: editorial_score >= 70 ? 'ready' : 'draft',
    tone_profile: 'vision7',
    topic: prev.topic,
    model_info: {
      model: 'gpt-4o-mini',
      source_count: prev.source_count,
      generated_at: new Date().toISOString()
    },
    moderation: audit,
    skip: false
  }
}];
